mapper.sql:
WHERE (#{scopeType} IS NULL OR run.scope_type = #{scopeType})
  AND (#{scopeId} IS NULL OR run.scope_id = #{scopeId})

  AND run.operation IN

      #{operation}



  AND run.status IN

      #{status}



  AND COALESCE(run.completed_at, run.started_at, run.queued_at, run.created_at) >= #{timeFrom}


  AND COALESCE(run.completed_at, run.started_at, run.queued_at, run.created_at) <= #{timeTo}


  AND (
      lower(run.id) LIKE '%' || #{keyword} || '%'
      OR lower(COALESCE(run.scope_id, '')) LIKE '%' || #{keyword} || '%'
      OR lower(COALESCE(run.current_item, '')) LIKE '%' || #{keyword} || '%'
      OR lower(COALESCE(run.error_message, '')) LIKE '%' || #{keyword} || '%'
      OR lower(COALESCE(folder.display_name, '')) LIKE '%' || #{keyword} || '%'
      OR lower(COALESCE(folder.folder_path, '')) LIKE '%' || #{keyword} || '%'
  )

mapper.select:
SELECT 
FROM knowledge_folder_runs run
WHERE run.id = #{id}

mapper.update:
UPDATE knowledge_folder_runs
SET status = 'CANCELLING',
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND status = 'RUNNING'

mapper.delete:
DELETE FROM knowledge_folder_runs
WHERE scope_type = #{scopeType}
  AND ((#{scopeId} IS NULL AND scope_id IS NULL) OR scope_id = #{scopeId})

DELETE FROM knowledge_folder_runs
WHERE id = #{id}
  AND status NOT IN ('QUEUED', 'RUNNING', 'CANCELLING')
